import React from "react";
import { Route, Routes, Navigate } from "react-router-dom";
import { useSelector } from "react-redux";
import ErrorBoundary from "./components/ErrorBoundary";
import Dashboard from "./pages/Dashboard";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Landing from "./pages/Landing";
import IncidentList from "./pages/IncidentList";
import SecurityTraining from "./pages/SecurityTraining";

import ThreatDetection from "./pages/features/ThreatDetection";
import ZeroTrust from "./pages/features/ZeroTrust";
import BlockchainAudit from "./pages/features/BlockchainAudit";
import QuantumCrypto from "./pages/features/QuantumCrypto";
import SOAR from "./pages/features/SOAR";
import Compliance from "./pages/features/Compliance";
import PrivacyML from "./pages/features/PrivacyML";
import Web3Identity from "./pages/features/Web3Identity";
import RASP from "./pages/features/RASP";
import DeceptiveSecurity from "./pages/features/DeceptiveSecurity";
import ConfidentialComputing from "./pages/features/ConfidentialComputing";
import SBOM from "./pages/features/SBOM";
import CloudAudits from "./pages/features/CloudAudits";
import RealTimeMonitoring from "./pages/features/RealTimeMonitoring";

import Product from "./pages/info/Product";
import Solutions from "./pages/info/Solutions";
import Pricing from "./pages/info/Pricing";
import Security from "./pages/info/Security";
import About from "./pages/info/About";
import Blog from "./pages/info/Blog";
import Careers from "./pages/info/Careers";
import Contact from "./pages/info/Contact";
import Resources from "./pages/info/Resources";
import Privacy from "./pages/info/Privacy";
import Terms from "./pages/info/Terms";

const PrivateRoute = ({ children }) => {
  const isAuthenticated = useSelector((state) => state.auth.isAuthenticated);
  const token = localStorage.getItem("access_token");

  if (!isAuthenticated && !token) {
    return <Navigate to="/login" replace />;
  }

  return children;
};

function App() {
  const isAuthenticated = useSelector((state) => state.auth.isAuthenticated);
  const token = localStorage.getItem("access_token");
  const isLoggedIn = isAuthenticated || token;

  return (
    <div className="App">
      <ErrorBoundary>
        <Routes>
          <Route path="/" element={isLoggedIn ? <Navigate to="/dashboard" /> : <Landing />} />
          <Route path="/landing" element={isLoggedIn ? <Navigate to="/dashboard" /> : <Landing />} />
          <Route path="/login" element={isLoggedIn ? <Navigate to="/dashboard" /> : <Login />} />
          <Route path="/register" element={isLoggedIn ? <Navigate to="/dashboard" /> : <Register />} />

          <Route path="/product" element={<Product />} />
          <Route path="/solutions" element={<Solutions />} />
          <Route path="/pricing" element={<Pricing />} />
          <Route path="/security" element={<Security />} />
          <Route path="/about" element={<About />} />
          <Route path="/blog" element={<Blog />} />
          <Route path="/careers" element={<Careers />} />
          <Route path="/contact" element={<Contact />} />
          <Route path="/resources" element={<Resources />} />
          <Route path="/privacy" element={<Privacy />} />
          <Route path="/terms" element={<Terms />} />

          <Route path="/features/threat-detection" element={<ThreatDetection />} />
          <Route path="/features/zero-trust" element={<ZeroTrust />} />
          <Route path="/features/blockchain-audit" element={<BlockchainAudit />} />
          <Route path="/features/quantum-crypto" element={<QuantumCrypto />} />
          <Route path="/features/soar" element={<SOAR />} />
          <Route path="/features/compliance" element={<Compliance />} />
          <Route path="/features/privacy-ml" element={<PrivacyML />} />
          <Route path="/features/web3-identity" element={<Web3Identity />} />
          <Route path="/features/rasp" element={<RASP />} />
          <Route path="/features/deceptive-security" element={<DeceptiveSecurity />} />
          <Route path="/features/confidential-computing" element={<ConfidentialComputing />} />
          <Route path="/features/sbom" element={<SBOM />} />
          <Route path="/features/cloud-audits" element={<CloudAudits />} />
          <Route path="/features/real-time-monitoring" element={<RealTimeMonitoring />} />

          <Route
            path="/dashboard"
            element={
              <PrivateRoute>
                <Dashboard />
              </PrivateRoute>
            }
          />
          <Route
            path="/incidents"
            element={
              <PrivateRoute>
                <IncidentList />
              </PrivateRoute>
            }
          />
          <Route
            path="/training"
            element={
              <PrivateRoute>
                <SecurityTraining />
              </PrivateRoute>
            }
          />
        </Routes>
      </ErrorBoundary>
    </div>
  );
}

export default App;
